# WEBSITE VISITOR IDENTIFICATION
# =============================================================================
CATEGORY_CONTENT["visitor-identification"] = {
 "definition": "de-anonymize website traffic by matching IP addresses, browser fingerprints, and behavioral signals to companies or individual contacts. These tools reveal which companies are visiting your site, what pages they view, and how long they engage, turning anonymous traffic into actionable sales intelligence.",
 "definition_expanded": "Website visitor identification has split into two tiers. Company-level identification uses reverse IP lookup to match visitors to their employer, revealing that someone from Acme Corp visited your pricing page. Person-level identification, a newer approach, attempts to match individual visitors using cookie data, ad network signals, and identity graphs. Company-level tools are mature and widely adopted. Person-level tools are more controversial, with ongoing debates about accuracy rates and privacy compliance.",
 "buying_guide": "Decide whether you need company-level or person-level identification. Company-level tools like Leadfeeder and Clearbit Reveal are established, GDPR-compliant, and identify 20-40% of B2B traffic reliably. Person-level tools like RB2B and Warmly claim to identify individual visitors with contact details, which is more actionable but comes with lower match rates and more privacy considerations. If you sell to enterprise accounts, company-level identification is usually sufficient since you can route the signal to the right rep based on account ownership.\n\nMatch rate is the metric that matters most, and it varies significantly by your traffic profile. B2B websites with enterprise visitors see higher identification rates because large companies have more consistent IP footprints. Sites with heavy mobile or remote-worker traffic see lower rates because residential IPs are harder to match. Run a free trial on your actual traffic before committing to a paid plan.\n\nThe real value comes from what happens after identification. A list of companies that visited your website is interesting but not actionable by itself. The best implementations route visitor data directly into sales workflows, triggering alerts when target accounts hit high-intent pages (pricing, case studies, competitor comparison), enriching visitors with contact data, and auto-creating tasks for reps. Evaluate how well each tool integrates with your CRM and engagement platform, not just its identification accuracy.",
 "faqs": [
 {"question": "How does website visitor identification work?", "answer": "Most tools use reverse IP lookup to match visitor IP addresses to company records. When someone visits your site from a corporate network, their IP maps to their employer. Person-level tools add cookie matching, ad network data, and identity resolution to attempt individual identification. Remote workers on home WiFi are harder to identify at the company level."},
 {"question": "What percentage of website visitors can be identified?", "answer": "Company-level tools typically identify 20-40% of B2B website traffic. Person-level tools claim 10-30% identification rates for individual visitors, though real-world results vary widely based on your traffic profile. Mobile visitors, VPN users, and remote workers on residential ISPs are the hardest to match."},
 {"question": "Is website visitor identification legal under GDPR?", "answer": "Company-level identification using reverse IP lookup is generally considered compliant under GDPR's legitimate interest basis for B2B purposes. Person-level identification is more complex and may require explicit consent depending on the jurisdiction and the data sources used. US-focused tools operate under less restrictive regulations. Consult your legal team if you serve European markets."},
 {"question": "What is the difference between RB2B and Leadfeeder?", "answer": "RB2B identifies individual visitors with names, emails, and LinkedIn profiles. Leadfeeder identifies companies visiting your site and shows which pages they viewed. RB2B gives you more actionable data per visitor but has lower match rates and only works for US traffic. Leadfeeder has broader geographic coverage and is more established but requires you to find the right contact at identified companies yourself."},
 {"question": "How do I get the most value from visitor identification?", "answer": "Connect visitor data to your sales workflow. Set up alerts for target accounts visiting high-intent pages like pricing or case studies. Auto-enrich identified visitors with contact data and create tasks for account owners. The teams that get ROI from visitor ID tools treat them as a signal layer feeding their existing outreach process, not as a standalone lead source."},
 ],
}

